// // Converts a 7-segment binary input into a BCD representation where the upper 4-bit output (outh) is the units place and the lower 4-bit output (outl) is the tens place.
module top_module(in, outh, outl);input [6:0]in;
    output [3:0]outh;
    output [3:0]outl;

    assign outh = in / 10;
    assign outl = in % 10;
endmodule
